65	// Returns all active users (id, name, lastname, email, profile_photo) for @mention autocomplete.
66	// profile_photo is the EFFECTIVE avatar: an uploaded photo if present, else the
67	// cached M365/Teams (Graph) photo — so the frontend needs no change. A bounded
68	// background backfill tops up stale users without blocking the response.
69	NotificationService.getMentionableUsers = async () => {
70	  const users = await sql.users.findAll({
71	    where: { status: 'active' },
72	    attributes: ['id', 'name', 'lastname', 'email', 'profile_photo', 'graph_photo', 'graph_photo_synced_at'],
73	    order: [['name', 'ASC']],
74	  });
75	  // Fire-and-forget: sync a few stale users' Graph photos for next time.
76	  GraphPhotoService.backfillStale(users).catch(() => {});
77	  return users.map((u) => ({
78	    id: u.id,
79	    name: u.name,
80	    lastname: u.lastname,
81	    email: u.email,
82	    profile_photo: GraphPhotoService.effectivePhoto(u),
83	  }));
84	};
85	
86	module.exports = NotificationService;
