11	const addComment = async (req, res) => {
12	    const data = await CommentService.addComment(req.body);
13	    res.json(data);
14	
15	    // Fire @mention notifications asynchronously — do not delay the response.
16	    const commentText = req.body.comment;
17	    const handles = parseMentions(commentText);
18	    if (handles.length) {
19	        try {
20	            const author = await getUserInfo(req.headers.authorization);
21	            const allUsers = await NotificationService.getMentionableUsers();
22	            const mentionedIds = resolveMentions(handles, allUsers);
23	            // Exclude the author from their own mention notifications.
24	            const targets = mentionedIds.filter(id => id !== author.user_id);
25	            if (targets.length) {
26	                const authorName = `${author.name || ''}`.trim() || author.email || 'Someone';
27	                await NotificationService.createManyNotifications(targets, {
28	                    type: 'mention',
29	                    event: 'comment_mention',
30	                    title: `${authorName} mentioned you`,
31	                    message: commentText.length > 200 ? commentText.slice(0, 197) + '...' : commentText,
32	                });
33	            }
34	        } catch (err) {
35	            // Non-fatal — log but don't affect the already-sent response.
36	            console.error('[mention notification error]', err.message);
37	        }
38	    }
39	}
