5	/**
6	 * Finds the best match for a given name from a list of options using string similarity.
7	 * @param {string} nameToMatch The name to find a match for (e.g., from the item description).
8	 * @param {Array<Object>} options The list of options to search through (e.g., all properties).
9	 * @param {string} key The key in the options object that holds the name.
10	 * @returns {Object|null} The best matching option object or null if no suitable match is found.
11	 */
12	const findBestMatch = (nameToMatch, options, key) => {
13	  if (!nameToMatch || !options || options.length === 0) {
14	    return null;
15	  }
16	
17	  let bestMatch = { score: 0, option: null };
18	
19	  for (const option of options) {
20	    // Calculate the similarity score between the item description and the option name.
21	    const score = stringSimilarity(nameToMatch.toLowerCase(), option[key].toLowerCase());
22	    if (score > bestMatch.score) {
23	      bestMatch = { score, option: option };
24	    }
25	  }
26	
27	  // We'll set a threshold (e.g., 0.4) to avoid incorrect low-confidence matches.
28	  // This value can be tuned based on testing.
29	  return bestMatch.score > 0.4 ? bestMatch.option : null;
30	};
