72	/**
73	 * Generates the autofill data object for a given SKU.
74	 * @param {string} sku The SKU (item_num_id) of the item.
75	 * @returns {Promise<Object|null>} The formatted autofill data or null if the item is not found.
76	 */
77	const generateAutofillData = async (sku) => {
78	  // 1. Fetch the main item details.
79	  const itemData = await getItemBySku(sku);
80	  const propertyData = await getPropertyById(itemData.udf_merchgroup06_fk_id);
81	  if (!itemData) {
82	    return null; // Item not found
83	  }
84	
85	  // 2. Fetch all available properties and characters from our new tables for matching.
86	  const schema = process.env.schema || process.env.SCHEMA;
87	  const [allProperties, allCharacters] = await Promise.all([
88	    sql.itemHeader.sequelize.query(`SELECT name FROM ${schema}.properties_and_characters WHERE type = 'PROPERTY'`, { type: sql.itemHeader.sequelize.QueryTypes.SELECT }),
89	    sql.itemHeader.sequelize.query(`SELECT name FROM ${schema}.properties_and_characters WHERE type = 'CHARACTER'`, { type: sql.itemHeader.sequelize.QueryTypes.SELECT })
90	  ]);
91	
92	  // 3. Perform fuzzy matching for properties and characters using the item's description.
93	  const propertyName = findBestMatch(propertyData.mg_desc, allProperties, 'name');
94	  const characterName = findBestMatch(itemData.item_descr_name, allCharacters, 'name');
95	
96	  const propertyCharacterNodes = [];
97	  // This logic assumes a character is always a child of a property.
98	  // It creates the nested array structure needed by the form.
99	  if (propertyName && characterName) {
100	    propertyCharacterNodes.push([propertyName, characterName]);
101	  } else if (propertyName) {
102	    // If only a property is found, add it alone.
103	    propertyCharacterNodes.push([propertyName]);
104	  }
105	
106	  // 4. Construct the final formData object in the desired format.
107	  const createdDate = new Date(itemData.created_time_date);
108	
109	  const formData = {
110	    product: {
111	      productName: itemData.item_descr_name || '',
112	      description: itemData.item_descr_name || '',
113	      sku: itemData.item_num_id || sku,
114	      upcException: 'This item does not have a UPC/EAN', // Default value
115	      businessJustification: 'Customer generates own UPC', // Default value
116	    },
117	    licensedMusicAndAudio: {
118	      includesMusic: 'No', // Default value
119	    },
120	    diversityEquityInclusion: {
121	      meetsDiversityClassification: 'No', // Default value
122	    },
123	    timingInformation: {
124	      // Using created_time_date as a placeholder for ship/shelf dates
125	      shipDateYear: createdDate.getFullYear().toString(),
126	      onShelfDateMonth: (createdDate.getMonth() + 1).toString(),
127	      onShelfDateYear: createdDate.getFullYear().toString(),
128	      season: itemData.season_code_fk_id ? 'Fall / Winter' : '', // Example mapping
129	      seasonYear: itemData.season_code_fk_id ? createdDate.getFullYear().toString() : '',
130	    },
131	    categoryAndProduct: {
132	      // This is a complex field. For now, we will leave it empty.
133	      // It would require a separate function to parse the `lobHierarchy` from Disney.json
134	      // and map it to the item's `udf_merchgroup` fields.
135	      selectedNodes: [],
136	    },
137	    productSet: {
138	      isProductSet: 'No', // Default value
139	    },
140	    propertiesAndCharacters: {
141	      selectedNodes: propertyCharacterNodes,
142	    },
143	    contractAndStyleGuide: {
144	      contractNumber: '', // Placeholder
145	      styleGuide: '', // Placeholder
146	    },
147	    marketInformation: {
148	      retailChannel: ['Mass Market Stores'], // Example default
149	      targetRetailers: [], // Placeholder
150	      otherRetailer: '',
151	      countryOfDistribution: ['USA'], // Example default
152	    },
153	    consumerSegment: ['Kids (6 To 8 Years)'], // Example default
154	    pricingInformation: {
155	      currency: 'USD - US Dollar',
156	      wholesalePrice: itemData.selling_price || '0.00',
157	      retailPrice: itemData.retail_price || '0.00',
158	    },
159	  };
160	
161	  return formData;
162	};
